INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_01$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The floor is damp. Not wet – damp. The kind of moisture that precedes a statement.$DQ$, $DQ$Der Boden ist feucht. Nicht nass – feucht. Die Art Feuchtigkeit, die einer Aussage vorausgeht.$DQ$, NULL, NULL, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_02$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Water at 12cm. Clear. The room is legible through it. That will change.$DQ$, $DQ$Wasser bei 12cm. Klar. Der Raum ist hindurch lesbar. Das wird sich ändern.$DQ$, NULL, NULL, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_03$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$12cm now. The sound of movement has changed – each action announces itself.$DQ$, $DQ$12cm jetzt. Das Geräusch der Bewegung hat sich verändert – jede Aktion kündigt sich an.$DQ$, NULL, NULL, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_04$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The waterline on the wall is 7cm higher than when the party entered this floor. The arithmetic is not complicated.$DQ$, $DQ$Die Wasserlinie an der Wand ist 7cm höher als beim Betreten dieser Etage. Die Arithmetik ist nicht kompliziert.$DQ$, NULL, NULL, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_05$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Half-submerged. The water is cold and has opinions about which direction the party should move.$DQ$, $DQ$Halb überflutet. Das Wasser ist kalt und hat Meinungen darüber, in welche Richtung sich die Gruppe bewegen sollte.$DQ$, NULL, NULL, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_06$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The current carries debris from rooms below. Fragments of encounters that are now depths.$DQ$, $DQ$Die Strömung trägt Trümmer aus Räumen darunter. Fragmente von Begegnungen, die jetzt Tiefen sind.$DQ$, NULL, NULL, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_07$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The surface is close. {agent} keeps the instruments above the waterline. Everything below is concession.$DQ$, $DQ$Die Oberfläche ist nah. {agent} hält die Instrumente über der Wasserlinie. Alles darunter ist Zugeständnis.$DQ$, NULL, NULL, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_08$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Three rooms above the waterline. Two hours ago there were five. The mathematics has not changed, only the denominator.$DQ$, $DQ$Drei Räume über der Wasserlinie. Vor zwei Stunden waren es fünf. Die Mathematik hat sich nicht geändert, nur der Nenner.$DQ$, NULL, NULL, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_09$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The water shifts. Something in the current organizes itself into opposition.$DQ$, $DQ$Das Wasser verlagert sich. Etwas in der Strömung ordnet sich zum Widerstand.$DQ$, NULL, NULL, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_10$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$Combat in water. Every action costs twice – once for the act, once for the medium.$DQ$, $DQ$Kampf im Wasser. Jede Aktion kostet doppelt – einmal für die Tat, einmal für das Medium.$DQ$, NULL, NULL, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_11$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_victory$DQ$, $JB${}$JB$::jsonb, $DQ$The current relents. Not defeated – redirected. It will find another path.$DQ$, $DQ$Die Strömung gibt nach. Nicht besiegt – umgelenkt. Sie wird einen anderen Weg finden.$DQ$, NULL, NULL, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_12$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_victory$DQ$, $JB${}$JB$::jsonb, $DQ$Quiet. The water level drops 2cm. The flood acknowledges the party$DQ$s right to this room. Temporarily.$DQ$, $DQ$Stille. Der Pegel sinkt um 2cm. Die Flut erkennt das Recht der Gruppe auf diesen Raum an. Vorübergehend.$DQ$, NULL, NULL, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_13$DQ$, $DQ$The Deluge$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$The current brought this. From below. From a room that is no longer a room – it is a depth.$DQ$, $DQ$Die Strömung brachte dies. Von unten. Aus einem Raum, der kein Raum mehr ist – er ist eine Tiefe.$DQ$, NULL, NULL, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_14$DQ$, $DQ$The Deluge$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$Salvaged. The water will want it back.$DQ$, $DQ$Geborgen. Das Wasser wird es zurückverlangen.$DQ$, NULL, NULL, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_15$DQ$, $DQ$The Deluge$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$Dry. The word has become a luxury. {agent} remains above the waterline and measures the silence.$DQ$, $DQ$Trocken. Das Wort ist zum Luxus geworden. {agent} verharrt über der Wasserlinie und misst die Stille.$DQ$, NULL, NULL, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_16$DQ$, $DQ$The Deluge$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$For a moment the water level stabilizes. Not recedes – stabilizes. In the Deluge, that is rest.$DQ$, $DQ$Für einen Moment stabilisiert sich der Pegel. Sinkt nicht – stabilisiert sich. In der Flut ist das Ruhe.$DQ$, NULL, NULL, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_17$DQ$, $DQ$The Deluge$DQ$, $DQ$tidal_recession$DQ$, $JB${}$JB$::jsonb, $DQ$The water pulls back. 8cm. A breath. Not generosity – mechanics. The tide returns.$DQ$, $DQ$Das Wasser zieht sich zurück. 8cm. Ein Atemzug. Keine Großzügigkeit – Mechanik. Die Flut kommt wieder.$DQ$, NULL, NULL, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_18$DQ$, $DQ$The Deluge$DQ$, $DQ$tidal_recession$DQ$, $JB${}$JB$::jsonb, $DQ$Recession. The watermarks on the wall tell two stories: how high the water was, and how high it will be.$DQ$, $DQ$Rückgang. Die Wasserzeichen an der Wand erzählen zwei Geschichten: wie hoch das Wasser war und wie hoch es sein wird.$DQ$, NULL, NULL, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_19$DQ$, $DQ$The Deluge$DQ$, $DQ$tidal_surge$DQ$, $JB${}$JB$::jsonb, $DQ$The tide returns. Higher. It always returns higher.$DQ$, $DQ$Die Flut kehrt zurück. Höher. Sie kehrt immer höher zurück.$DQ$, NULL, NULL, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_20$DQ$, $DQ$The Deluge$DQ$, $DQ$ankle_threshold$DQ$, $JB${}$JB$::jsonb, $DQ$The water has reached the third step. It does not rush. It has been doing this for longer than the stairwell has existed.$DQ$, $DQ$Das Wasser hat die dritte Stufe erreicht. Es eilt nicht. Es tut dies seit länger als das Treppenhaus existiert.$DQ$, NULL, NULL, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_21$DQ$, $DQ$The Deluge$DQ$, $DQ$waist_threshold$DQ$, $JB${}$JB$::jsonb, $DQ$Half-submerged. The operational vocabulary contracts. Salvage. Seal. Ascend.$DQ$, $DQ$Halb überflutet. Das operative Vokabular schrumpft. Bergen. Abdichten. Aufsteigen.$DQ$, NULL, NULL, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_22$DQ$, $DQ$The Deluge$DQ$, $DQ$chest_threshold$DQ$, $JB${}$JB$::jsonb, $DQ$»Der Pegel steigt. Nicht schnell. Er hat Zeit. Er hatte immer Zeit.«$DQ$, $DQ$»Der Pegel steigt. Nicht schnell. Er hat Zeit. Er hatte immer Zeit.«$DQ$, NULL, NULL, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_23$DQ$, $DQ$The Deluge$DQ$, $DQ$flood_imminent$DQ$, $JB${}$JB$::jsonb, $DQ$Cold. Rising. {agent} adjusts. There is nothing else to adjust.$DQ$, $DQ$Kalt. Steigend. {agent} passt sich an. Es gibt nichts anderes anzupassen.$DQ$, NULL, NULL, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_24$DQ$, $DQ$The Deluge$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The party ascends. Behind them, the water fills what they leave. No sound of pursuit – only the sound of level.$DQ$, $DQ$Die Gruppe steigt auf. Hinter ihnen füllt das Wasser, was sie verlassen. Kein Geräusch der Verfolgung – nur das Geräusch des Pegels.$DQ$, NULL, NULL, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_25$DQ$, $DQ$The Deluge$DQ$, $DQ$submerged_room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The submerged corridor is beautiful. {agent} was not prepared for that.$DQ$, $DQ$Der überflutete Korridor ist schön. {agent} war darauf nicht vorbereitet.$DQ$, NULL, NULL, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($DQ$db_26$DQ$, $DQ$The Deluge$DQ$, $DQ$submerged_room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Under the surface, the room has reorganized itself. What was ceiling is now a mirror. What was door is now a passage to somewhere the map does not name.$DQ$, $DQ$Unter der Oberfläche hat sich der Raum neu geordnet. Was Decke war, ist jetzt ein Spiegel. Was Tür war, ist jetzt ein Durchgang zu etwas, das die Karte nicht benennt.$DQ$, NULL, NULL, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_riptide_tendril$DQ$, $DQ$The Deluge$DQ$, $DQ$Riptide Tendril$DQ$, $DQ$Sogranke$DQ$, 1, 20, $DQ$minion$DQ$, $DQ$assassin$DQ$, 2, 3, true, 40, ARRAY[$DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$guardian$DQ$]::TEXT[], $JB${"attack": 40, "drag": 30, "evade": 20, "ambient": 10}$JB$::jsonb, ARRAY[$DQ$drag$DQ$]::TEXT[], $DQ$A current given form. It does not strike – it pulls. The direction is always down, always toward deeper water.$DQ$, $DQ$Eine Strömung, die Form angenommen hat. Sie schlägt nicht zu – sie zieht. Die Richtung ist immer abwärts, immer in tieferes Wasser.$DQ$, ARRAY[$DQ$The tendril tests the space between {agent}$DQ$s feet and the floor.$DQ$, $DQ$Something in the current reaches. Not aggressively – patiently.$DQ$]::TEXT[], ARRAY[$DQ$Die Ranke prüft den Raum zwischen {agent}s Füßen und dem Boden.$DQ$, $DQ$Etwas in der Strömung greift. Nicht aggressiv – geduldig.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_pressure_surge$DQ$, $DQ$The Deluge$DQ$, $DQ$Pressure Surge$DQ$, $DQ$Druckwelle$DQ$, 2, 100, $DQ$standard$DQ$, $DQ$guardian$DQ$, 4, 5, true, 10, ARRAY[$DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$spy$DQ$]::TEXT[], $JB${"attack": 45, "flood_pulse": 30, "stress_attack": 15, "ambient": 10}$JB$::jsonb, ARRAY[$DQ$flood_pulse$DQ$]::TEXT[], $DQ$The water$DQ$s memory of what it once displaced. It arrives as a wall – not tall, not dramatic, but dense. The kind of force that moves furniture and doesn$DQ$t notice.$DQ$, $DQ$Die Erinnerung des Wassers an das, was es einst verdrängte. Es kommt als Wand – nicht hoch, nicht dramatisch, aber dicht. Die Art Kraft, die Möbel verschiebt und es nicht bemerkt.$DQ$, ARRAY[$DQ$The water level in the room rises 2cm. Then 2cm more. Then stops.$DQ$, $DQ$The pressure surge gathers. {agent} feels it in the floor before seeing it.$DQ$]::TEXT[], ARRAY[$DQ$Der Pegel im Raum steigt um 2cm. Dann nochmal 2cm. Dann hört es auf.$DQ$, $DQ${agent} spürt die Druckwelle im Boden, bevor sie sichtbar wird.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_silt_revenant$DQ$, $DQ$The Deluge$DQ$, $DQ$Silt Revenant$DQ$, $DQ$Schlickwiedergänger$DQ$, 3, 60, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 3, 6, true, 15, ARRAY[$DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"stress_attack": 40, "obscure": 30, "attack": 20, "ambient": 10}$JB$::jsonb, ARRAY[$DQ$obscure$DQ$]::TEXT[], $DQ$It emerged from the sediment when the water reached this level. A shape made of what the flood deposited – silt, mineral, the residue of dissolved rooms. It does not speak. It broadcasts the sound of water in enclosed spaces.$DQ$, $DQ$Es stieg aus dem Sediment, als das Wasser diesen Pegel erreichte. Eine Gestalt aus dem, was die Flut ablagerte – Schlick, Mineral, der Rückstand aufgelöster Räume. Es spricht nicht. Es sendet das Geräusch von Wasser in geschlossenen Räumen.$DQ$, ARRAY[$DQ$The revenant shifts. Silt falls from it like memory from a dream.$DQ$, $DQ${agent} recognizes something in the revenant$DQ$s shape. A doorframe. A railing.$DQ$]::TEXT[], ARRAY[$DQ$Der Wiedergänger bewegt sich. Schlick fällt von ihm wie Erinnerung aus einem Traum.$DQ$, $DQ${agent} erkennt etwas in der Form des Wiedergängers. Einen Türrahmen. Ein Geländer.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_undertow_warden$DQ$, $DQ$The Deluge$DQ$, $DQ$Undertow Warden$DQ$, $DQ$Sogwächter$DQ$, 4, 200, $DQ$elite$DQ$, $DQ$guardian$DQ$, 5, 6, true, 5, ARRAY[$DQ$assassin$DQ$, $DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"attack": 35, "drag": 25, "flood_pulse": 20, "stress_attack": 10, "ambient": 10}$JB$::jsonb, ARRAY[$DQ$drag$DQ$, $DQ$flood_pulse$DQ$]::TEXT[], $DQ$The water$DQ$s enforcer. Not an entity that lives in water – an entity that IS water, given mass and purpose. It does not guard a door. It guards a depth.$DQ$, $DQ$Der Vollstrecker des Wassers. Keine Entität, die im Wasser lebt – eine Entität, die Wasser IST, mit Masse und Absicht versehen. Es bewacht keine Tür. Es bewacht eine Tiefe.$DQ$, ARRAY[$DQ$The warden does not approach. The water level in the room rises to meet it.$DQ$, $DQ$Its shape changes with the current. {agent} cannot determine where it begins.$DQ$]::TEXT[], ARRAY[$DQ$Der Wächter nähert sich nicht. Der Pegel im Raum steigt, um ihm entgegenzukommen.$DQ$, $DQ$Seine Form ändert sich mit der Strömung. {agent} kann nicht bestimmen, wo er beginnt.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_the_current$DQ$, $DQ$The Deluge$DQ$, $DQ$The Current$DQ$, $DQ$Die Strömung$DQ$, 6, 350, $DQ$boss$DQ$, $DQ$guardian$DQ$, 6, 8, false, 0, ARRAY[$DQ$assassin$DQ$, $DQ$infiltrator$DQ$, $DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"attack": 30, "flood_pulse": 25, "drag": 20, "tidal_wave": 15, "ambient": 10}$JB$::jsonb, ARRAY[$DQ$flood_pulse$DQ$, $DQ$drag$DQ$, $DQ$tidal_wave$DQ$]::TEXT[], $DQ$Not an enemy. A direction. The Current is the flood$DQ$s final argument: that everything flows downward, that every barrier is temporary, that what the water claims, the water keeps. It does not attack. It arrives.$DQ$, $DQ$Kein Feind. Eine Richtung. Die Strömung ist das letzte Argument der Flut: dass alles abwärts fließt, dass jede Barriere vorübergehend ist, dass was das Wasser beansprucht, das Wasser behält. Sie greift nicht an. Sie kommt.$DQ$, ARRAY[$DQ$The Current fills the room. Not like water entering – like water remembering it was always here.$DQ$, $DQ$The walls are underwater. The ceiling is not. For now.$DQ$]::TEXT[], ARRAY[$DQ$Die Strömung füllt den Raum. Nicht wie einströmendes Wasser – wie Wasser, das sich erinnert, schon immer hier gewesen zu sein.$DQ$, $DQ$Die Wände sind unter Wasser. Die Decke nicht. Noch nicht.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($DQ$deluge_trickle_spawn$DQ$, $DQ$The Deluge$DQ$, $JB$[{"template_id": "deluge_riptide_tendril", "count": 2}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
