INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($DQ$deluge_warden_spawn$DQ$, $DQ$The Deluge$DQ$, $JB$[{"template_id": "deluge_undertow_warden", "count": 1}, {"template_id": "deluge_riptide_tendril", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($DQ$deluge_rest_ambush_spawn$DQ$, $DQ$The Deluge$DQ$, $JB$[{"template_id": "deluge_riptide_tendril", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_trickle_probe$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 1, 3, 1, NULL, $DQ$First currents testing the party$DQ$s resolve. Two tendrils of water extend from the floor drain, probing the space the party occupies. They are not fast. They are patient.$DQ$, $DQ$Erste Strömungen, die die Entschlossenheit der Gruppe testen. Zwei Wasserranken strecken sich aus dem Bodenabfluss, tasten den Raum ab, den die Gruppe einnimmt. Sie sind nicht schnell. Sie sind geduldig.$DQ$, $DQ$deluge_trickle_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_surge_corridor$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 2, 4, 1, NULL, $DQ$A corridor where the water moves with purpose. A Pressure Surge occupies the center – a wall of dense water that advances without hurry. A Riptide Tendril flanks from the drainage channel. The corridor narrows. The water does not.$DQ$, $DQ$Ein Korridor, in dem das Wasser sich mit Absicht bewegt. Eine Druckwelle besetzt die Mitte – eine Wand dichten Wassers, die ohne Eile vorrückt. Eine Sogranke flankiert aus dem Abflusskanal. Der Korridor verengt sich. Das Wasser nicht.$DQ$, $DQ$deluge_surge_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_sediment_ambush$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 2, 5, 1, NULL, $DQ$The silt remembers shapes. Some of them fight back. A Silt Revenant assembles from the sediment layer – mineral, debris, the residue of dissolved architecture. A tendril assists, pulling from below.$DQ$, $DQ$Der Schlick erinnert sich an Formen. Einige davon wehren sich. Ein Schlickwiedergänger setzt sich aus der Sedimentschicht zusammen – Mineral, Trümmer, der Rückstand aufgelöster Architektur. Eine Ranke assistiert und zieht von unten.$DQ$, $DQ$deluge_sediment_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_deep_water_clash$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 3, 6, 2, NULL, $DQ$Waist-deep. Every step costs something. A Pressure Surge and a Silt Revenant occupy a junction room where three corridors meet. The water here has momentum – it flows, it carries, it resists.$DQ$, $DQ$Hüfttief. Jeder Schritt kostet. Eine Druckwelle und ein Schlickwiedergänger besetzen einen Knotenpunkt, an dem drei Korridore zusammentreffen. Das Wasser hier hat Schwung – es fließt, es trägt, es widersteht.$DQ$, $DQ$deluge_deep_water_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_warden_chamber$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 4, 7, 2, NULL, $DQ$The water has posted a guard at this depth. An Undertow Warden – water given mass and purpose – fills the chamber. A tendril circles the perimeter. The warden does not approach. The water level rises to meet it.$DQ$, $DQ$Das Wasser hat einen Wächter auf dieser Tiefe postiert. Ein Sogwächter – Wasser mit Masse und Absicht versehen – füllt die Kammer. Eine Ranke umkreist den Rand. Der Wächter nähert sich nicht. Der Pegel steigt, um ihm entgegenzukommen.$DQ$, $DQ$deluge_warden_spawn$DQ$, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_whirlpool_room$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 3, 5, 2, NULL, $DQ$The current circles. The party is in the center. A Pressure Surge and a Silt Revenant orbit the room$DQ$s perimeter, riding the whirlpool. Fighting here means fighting the water$DQ$s geometry.$DQ$, $DQ$Die Strömung kreist. Die Gruppe ist im Zentrum. Eine Druckwelle und ein Schlickwiedergänger umkreisen den Raumrand, reiten auf dem Strudel. Hier kämpfen heißt gegen die Geometrie des Wassers kämpfen.$DQ$, $DQ$deluge_deep_water_spawn$DQ$, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_the_watermark$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$A line on the wall. Faint. Mineral-white. The watermark shows how high the water reached last time.$DQ$, $DQ$Eine Linie an der Wand. Schwach. Mineralweiß. Das Wasserzeichen zeigt, wie hoch das Wasser beim letzten Mal stand.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_submerged_cache$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$Through the water below – shapes. Containers. Something the flood deposited here from a room that no longer exists.$DQ$, $DQ$Durch das Wasser darunter – Formen. Behälter. Etwas, das die Flut hier ablagerte, aus einem Raum, der nicht mehr existiert.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_the_breach$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 2, 5, 1, NULL, $DQ$A crack in the wall. Water doesn$DQ$t pour through it – it persuades. A thin, persistent line of moisture that widens as you watch.$DQ$, $DQ$Ein Riss in der Wand. Wasser strömt nicht hindurch – es überredet. Eine dünne, beharrliche Feuchtigkeitslinie, die sich verbreitert, während man zusieht.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_survivors_message$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$Carved into the wall above the current waterline. Recent. Someone else tried this. The message is incomplete – the water reached it before they finished.$DQ$, $DQ$In die Wand geritzt, über der aktuellen Wasserlinie. Kürzlich. Jemand anderes hat dies versucht. Die Nachricht ist unvollständig – das Wasser erreichte sie, bevor sie fertig waren.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_sound_of_depth$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 3, 6, 2, NULL, $DQ$The water below has reached a resonance. A low hum. Not mechanical – geological. The sound the planet makes when it remembers it is mostly ocean.$DQ$, $DQ$Das Wasser darunter hat eine Resonanz erreicht. Ein tiefes Summen. Nicht mechanisch – geologisch. Das Geräusch, das der Planet macht, wenn er sich erinnert, dass er hauptsächlich Ozean ist.$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_tidal_gate$DQ$, $DQ$The Deluge$DQ$, $DQ$elite$DQ$, 4, 6, 1, NULL, $DQ$A mechanism. Ancient. Not built by anyone in this simulation. The gate controls a section of the flood – open it and the water surges through, closed it holds. But the mechanism requires a sacrifice.$DQ$, $DQ$Ein Mechanismus. Uralt. Nicht von jemandem in dieser Simulation erbaut. Das Tor kontrolliert einen Abschnitt der Flut – öffnet man es, bricht das Wasser durch; geschlossen hält es. Aber der Mechanismus fordert ein Opfer.$DQ$, $DQ$deluge_warden_spawn$DQ$, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_the_current_boss$DQ$, $DQ$The Deluge$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The water has found its shape. It fills the room from below, from the walls, from the ceiling. The Current is not something IN the water. The Current IS the water, organized into purpose. It does not attack. It arrives.$DQ$, $DQ$Das Wasser hat seine Form gefunden. Es füllt den Raum von unten, von den Wänden, von der Decke. Die Strömung ist nicht etwas IM Wasser. Die Strömung IST das Wasser, zu Absicht organisiert. Sie greift nicht an. Sie kommt.$DQ$, $DQ$deluge_warden_spawn$DQ$, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_dry_shelf$DQ$, $DQ$The Deluge$DQ$, $DQ$rest$DQ$, 1, 99, 1, NULL, $DQ$A ledge. Above the current waterline. Dry, for now. The mathematical certainty of the rising water makes this rest temporary, but temporary is enough.$DQ$, $DQ$Ein Vorsprung. Über der aktuellen Wasserlinie. Trocken, vorerst. Die mathematische Gewissheit des steigenden Wassers macht diese Rast vorübergehend, aber vorübergehend reicht.$DQ$, NULL, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_air_pocket$DQ$, $DQ$The Deluge$DQ$, $DQ$rest$DQ$, 3, 99, 1, NULL, $DQ$A pocket of trapped air in a partially flooded section. The ceiling is close. The water is at chest height. But the air is breathable and the current is still.$DQ$, $DQ$Eine Lufttasche in einem teilweise überfluteten Abschnitt. Die Decke ist nah. Das Wasser steht auf Brusthöhe. Aber die Luft ist atembar und die Strömung ist ruhig.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_flotsam_cache$DQ$, $DQ$The Deluge$DQ$, $DQ$treasure$DQ$, 1, 99, 1, NULL, $DQ$The current deposited this. From where? From a room that is no longer above the waterline. The objects are waterlogged but intact.$DQ$, $DQ$Die Strömung lagerte dies ab. Woher? Aus einem Raum, der nicht mehr über der Wasserlinie liegt. Die Objekte sind durchnässt, aber intakt.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_preserved_chamber$DQ$, $DQ$The Deluge$DQ$, $DQ$treasure$DQ$, 2, 99, 1, NULL, $DQ$Someone sealed this room. The seal held – until now. Inside, everything is dry. The dust on the surfaces has not been disturbed by water. A time capsule from before the flood.$DQ$, $DQ$Jemand hat diesen Raum versiegelt. Das Siegel hielt – bis jetzt. Drinnen ist alles trocken. Der Staub auf den Oberflächen wurde nicht vom Wasser gestört. Eine Zeitkapsel von vor der Flut.$DQ$, NULL, false, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$watermark_study$DQ$, $DQ$dc_the_watermark$DQ$, $DQ$Study the watermark (Spy)$DQ$, $DQ$Das Wasserzeichen studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"water_level": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"water_level": 3}$JB$::jsonb, $DQ$The pattern reveals itself. {agent} reads the intervals between marks – the tide$DQ$s rhythm, predictable as breathing. The next recession will be stronger.$DQ$, $DQ${agent} liest die Abstände zwischen den Markierungen – der Rhythmus der Gezeiten, vorhersagbar wie Atmen. Der nächste Rückgang wird stärker sein.$DQ$, NULL, NULL, $DQ$The marks blur. Time wasted. The water does not wait for comprehension.$DQ$, $DQ$Die Markierungen verschwimmen. Verschwendete Zeit. Das Wasser wartet nicht auf Verständnis.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$watermark_seal$DQ$, $DQ$dc_the_watermark$DQ$, $DQ$Seal below the mark (Guardian)$DQ$, $DQ$Unterhalb der Markierung abdichten (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, -5, $JB${"water_level": -8}$JB$::jsonb, $JB${"water_level": -4}$JB$::jsonb, $JB${"water_level": 5}$JB$::jsonb, $DQ$The seal holds. The water below the mark is contained – for now. {agent}$DQ$s hands are raw but the arithmetic improves.$DQ$, $DQ$Die Abdichtung hält. Das Wasser unterhalb der Markierung ist eingedämmt – vorerst. {agent}s Hände sind wund, aber die Arithmetik verbessert sich.$DQ$, NULL, NULL, $DQ$The seal breaches. The water finds the weakness before {agent} can reinforce it.$DQ$, $DQ$Die Abdichtung bricht. Das Wasser findet die Schwachstelle, bevor {agent} sie verstärken kann.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$watermark_ignore$DQ$, $DQ$dc_the_watermark$DQ$, $DQ$Ignore it and move$DQ$, $DQ$Ignorieren und weitergehen$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party moves on. The watermark remains.$DQ$, $DQ$Die Gruppe geht weiter. Das Wasserzeichen bleibt.$DQ$, NULL, NULL, NULL, NULL, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cache_dive$DQ$, $DQ$dc_submerged_cache$DQ$, $DQ$Dive for it (Guardian)$DQ$, $DQ$Danach tauchen (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, -5, $JB${"loot_tier": 2}$JB$::jsonb, $JB${"loot_tier": 1, "stress": 10}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ${agent} surfaces with a sealed container. The contents are dry. The flood carried this from somewhere valuable.$DQ$, $DQ${agent} taucht mit einem versiegelten Behälter auf. Der Inhalt ist trocken. Die Flut trug dies von irgendwo Wertvollem hierher.$DQ$, NULL, NULL, $DQ$The current pulls {agent} deeper than intended. Nothing retrieved. Stress accumulated.$DQ$, $DQ$Die Strömung zieht {agent} tiefer als beabsichtigt. Nichts geborgen. Stress angesammelt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cache_eyes$DQ$, $DQ$dc_submerged_cache$DQ$, $DQ$Send the sharpest eyes (Spy)$DQ$, $DQ$Die schärfsten Augen schicken (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"loot_tier": 2}$JB$::jsonb, $JB${"loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ${agent} identifies the best container through the water$DQ$s distortion. Precise. The flood reveals to those who observe.$DQ$, $DQ${agent} identifiziert den besten Behälter durch die Verzerrung des Wassers. Präzise. Die Flut offenbart sich denen, die beobachten.$DQ$, NULL, NULL, $DQ$The water distorts. Nothing distinct. The flood keeps its inventory.$DQ$, $DQ$Das Wasser verzerrt. Nichts Deutliches. Die Flut behält ihr Inventar.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cache_leave$DQ$, $DQ$dc_submerged_cache$DQ$, $DQ$Leave it. The water owns it now.$DQ$, $DQ$Es lassen. Das Wasser besitzt es jetzt.$DQ$, NULL, NULL, NULL, 0, $JB${"stress": -5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party moves on. The containers settle. Acceptance is its own economy.$DQ$, $DQ$Die Gruppe geht weiter. Die Behälter setzen sich ab. Akzeptanz ist ihre eigene Ökonomie.$DQ$, NULL, NULL, NULL, NULL, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$breach_seal$DQ$, $DQ$dc_the_breach$DQ$, $DQ$Seal it (Saboteur)$DQ$, $DQ$Abdichten (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, -5, $JB${"water_level": -10}$JB$::jsonb, $JB${"water_level": -5}$JB$::jsonb, $JB${"water_level": 8}$JB$::jsonb, $DQ$The breach is sealed. {agent}$DQ$s work is precise – the kind of engineering that holds against water$DQ$s patience.$DQ$, $DQ$Die Bresche ist abgedichtet. {agent}s Arbeit ist präzise – die Art Ingenieurkunst, die der Geduld des Wassers standhält.$DQ$, NULL, NULL, $DQ$The breach widens. The water had already planned for this.$DQ$, $DQ$Die Bresche verbreitert sich. Das Wasser hatte dies bereits eingeplant.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$breach_redirect$DQ$, $DQ$dc_the_breach$DQ$, $DQ$Redirect it (Spy)$DQ$, $DQ$Umleiten (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"water_level": -5}$JB$::jsonb, $JB${"water_level": -2}$JB$::jsonb, $JB${"water_level": 5}$JB$::jsonb, $DQ${agent} reads the water$DQ$s intent and redirects the flow into an adjacent corridor. The breach remains, but its consequences are elsewhere.$DQ$, $DQ${agent} liest die Absicht des Wassers und lenkt den Fluss in einen benachbarten Korridor. Die Bresche bleibt, aber ihre Konsequenzen sind anderswo.$DQ$, NULL, NULL, $DQ$The redirection fails. The water knows this route better.$DQ$, $DQ$Die Umleitung scheitert. Das Wasser kennt diesen Weg besser.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$breach_use$DQ$, $DQ$dc_the_breach$DQ$, $DQ$Use it (Assassin)$DQ$, $DQ$Ausnutzen (Assassine)$DQ$, NULL, NULL, $DQ$assassin$DQ$, 0, $JB${"water_level": 3, "next_combat_bonus": "enemy_condition_step"}$JB$::jsonb, $JB${"water_level": 5}$JB$::jsonb, $JB${"water_level": 10}$JB$::jsonb, $DQ${agent} weaponizes the breach. The next combat will begin with enemies already battered by the water$DQ$s force.$DQ$, $DQ${agent} macht die Bresche zur Waffe. Der nächste Kampf beginnt mit Feinden, die bereits von der Kraft des Wassers geschwächt sind.$DQ$, NULL, NULL, $DQ$The breach becomes a flood. The water does not serve.$DQ$, $DQ$Die Bresche wird zur Flut. Das Wasser dient nicht.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$message_read$DQ$, $DQ$dc_survivors_message$DQ$, $DQ$Read what remains (Propagandist)$DQ$, $DQ$Lesen, was bleibt (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, -5, $JB${"reveal_rooms": 2}$JB$::jsonb, $JB${"reveal_rooms": 1}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$The message is a map. Partial, but legible. {agent} decodes the previous party$DQ$s observations – room types, water routes, a warning about the depth below.$DQ$, $DQ$Die Nachricht ist eine Karte. Unvollständig, aber lesbar. {agent} entschlüsselt die Beobachtungen der vorherigen Gruppe – Raumtypen, Wasserwege, eine Warnung über die Tiefe darunter.$DQ$, NULL, NULL, $DQ$The message is unsettling. The handwriting deteriorates. The last word is either $DQ$rising$DQ$ or $DQ$run$DQ$.$DQ$, $DQ$Die Nachricht ist beunruhigend. Die Handschrift verschlechtert sich. Das letzte Wort ist entweder »steigend« oder »lauf«.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$message_add$DQ$, $DQ$dc_survivors_message$DQ$, $DQ$Add to it (Spy)$DQ$, $DQ$Ergänzen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"water_level": 3}$JB$::jsonb, $DQ${agent} carves observations into the wall. Precise. Economical. Future parties will find better intelligence.$DQ$, $DQ${agent} ritzt Beobachtungen in die Wand. Präzise. Ökonomisch. Zukünftige Gruppen werden bessere Informationen finden.$DQ$, NULL, NULL, $DQ$Time wasted. The water rises while {agent} carves.$DQ$, $DQ$Verschwendete Zeit. Das Wasser steigt, während {agent} ritzt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$depth_listen$DQ$, $DQ$dc_sound_of_depth$DQ$, $DQ$Listen (Propagandist)$DQ$, $DQ$Lauschen (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 0, $JB${"boss_intel": "first_attack_crit"}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"stress": 10}$JB$::jsonb, $DQ$The resonance reveals a pattern. {agent} understands – the boss$DQ$s rhythm, its weakness. The first strike will find the fault line.$DQ$, $DQ$Die Resonanz offenbart ein Muster. {agent} versteht – den Rhythmus des Bosses, seine Schwäche. Der erste Schlag wird die Bruchlinie finden.$DQ$, NULL, NULL, $DQ$The sound is disorienting. It fills {agent}$DQ$s head and refuses to leave.$DQ$, $DQ$Das Geräusch ist desorientierend. Es füllt {agent}s Kopf und weigert sich zu gehen.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$depth_measure$DQ$, $DQ$dc_sound_of_depth$DQ$, $DQ$Measure it (Spy)$DQ$, $DQ$Vermessen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"reveal_water_calc": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Precise calculations. {agent} now knows exactly how many rooms remain before the submerged threshold. The arithmetic is merciless but clear.$DQ$, $DQ$Präzise Berechnungen. {agent} weiß jetzt genau, wie viele Räume bis zur Überschwemmungsschwelle verbleiben. Die Arithmetik ist gnadenlos, aber klar.$DQ$, NULL, NULL, $DQ$Instruments damaged. The water$DQ$s vibration is not compatible with measurement.$DQ$, $DQ$Instrumente beschädigt. Die Vibration des Wassers ist nicht messungskompatibel.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$depth_block$DQ$, $DQ$dc_sound_of_depth$DQ$, $DQ$Block it out$DQ$, $DQ$Ausblenden$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party moves on. The sound continues without them.$DQ$, $DQ$Die Gruppe geht weiter. Das Geräusch setzt sich ohne sie fort.$DQ$, NULL, NULL, NULL, NULL, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dry_shelf_rest$DQ$, $DQ$dc_dry_shelf$DQ$, $DQ$Rest on the dry shelf$DQ$, $DQ$Auf dem trockenen Vorsprung rasten$DQ$, NULL, NULL, NULL, 0, $JB${"stress_heal": 40, "water_level": -5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests. The water level drops slightly – pumping, seepage, the ledge$DQ$s drainage. When they rise, the waterline is 5cm lower. It will not stay there.$DQ$, $DQ$Die Gruppe rastet. Der Pegel sinkt leicht – Pumpen, Sickern, die Drainage des Vorsprungs. Als sie aufstehen, ist die Wasserlinie 5cm niedriger. Sie wird nicht dort bleiben.$DQ$, NULL, NULL, NULL, NULL, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$air_pocket_rest$DQ$, $DQ$dc_air_pocket$DQ$, $DQ$Rest in the air pocket$DQ$, $DQ$In der Lufttasche rasten$DQ$, NULL, NULL, NULL, 0, $JB${"stress_heal": 25, "water_level": -3, "stress": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Reduced rest. Not comfortable – the ceiling is close, the water is cold. But the current is still and the air is breathable. Claustrophobia is the price of shelter.$DQ$, $DQ$Eingeschränkte Rast. Nicht bequem – die Decke ist nah, das Wasser ist kalt. Aber die Strömung ist ruhig und die Luft atembar. Klaustrophobie ist der Preis für Schutz.$DQ$, NULL, NULL, NULL, NULL, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$flotsam_take$DQ$, $DQ$dc_flotsam_cache$DQ$, $DQ$Salvage the flotsam$DQ$, $DQ$Das Treibgut bergen$DQ$, NULL, NULL, NULL, 0, $JB${"loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Salvaged. The water will want it back.$DQ$, $DQ$Geborgen. Das Wasser wird es zurückverlangen.$DQ$, NULL, NULL, NULL, NULL, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$preserved_open$DQ$, $DQ$dc_preserved_chamber$DQ$, $DQ$Open the sealed chamber$DQ$, $DQ$Die versiegelte Kammer öffnen$DQ$, NULL, NULL, NULL, 0, $JB${"loot_tier": 2, "water_level": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The seal breaks. Quality salvage inside – dry, preserved, valuable. But the seal is now broken. The room will flood on the next tidal surge.$DQ$, $DQ$Das Siegel bricht. Qualitätsgut drinnen – trocken, konserviert, wertvoll. Aber das Siegel ist jetzt gebrochen. Der Raum wird beim nächsten Gezeitenstoß überflutet.$DQ$, NULL, NULL, NULL, NULL, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_brine_residue$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Brine Residue$DQ$, $DQ$Salzrückstand$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$Crystallized from evaporated floodwater. Holding it steadies the pulse. A mineral memory of when the water was calm.$DQ$, $DQ$Kristallisiert aus verdunstetem Flutwasser. Es in der Hand zu halten beruhigt den Puls. Eine mineralische Erinnerung daran, als das Wasser ruhig war.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_tide_reading$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Tide Reading$DQ$, $DQ$Gezeitenablesung$DQ$, $DQ$memory$DQ$, $JB${"importance": 4, "content_en": "Learned to read the intervals between surges. Not prediction – recognition.", "content_de": "Gelernt, die Intervalle zwischen den Fluten zu lesen. Keine Vorhersage – Wiedererkennung."}$JB$::jsonb, $DQ$Learned to read the intervals between surges. Not prediction – recognition.$DQ$, $DQ$Gelernt, die Intervalle zwischen den Fluten zu lesen. Keine Vorhersage – Wiedererkennung.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_seal_fragment$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Seal Fragment$DQ$, $DQ$Dichtungsfragment$DQ$, $DQ$dungeon_buff$DQ$, $JB${"check_bonus": 5, "aptitude": "guardian", "scope": "this_dungeon"}$JB$::jsonb, $DQ$A piece of whatever held the water back before the party arrived. Guardian checks +5%.$DQ$, $DQ$Ein Stück dessen, was das Wasser zurückhielt, bevor die Gruppe ankam. Wächter-Proben +5%.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_current_map$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Current Map$DQ$, $DQ$Strömungskarte$DQ$, $DQ$dungeon_buff$DQ$, $JB${"check_bonus": 5, "aptitude": "spy", "scope": "this_dungeon"}$JB$::jsonb, $DQ$A trace of the water$DQ$s preferred paths. Spy checks +5%.$DQ$, $DQ$Eine Spur der bevorzugten Wege des Wassers. Spion-Proben +5%.$DQ$, 20, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_pressure_ward$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Pressure Ward$DQ$, $DQ$Druckschutz$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 120, "when": "after_dungeon"}$JB$::jsonb, $DQ$Equalized pressure from a sealed chamber. The relief is physical – the tension in the chest that was always there, gone.$DQ$, $DQ$Ausgeglichener Druck aus einer versiegelten Kammer. Die Erleichterung ist physisch – die Spannung in der Brust, die immer da war, weg.$DQ$, 30, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_salvage_record$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Salvage Record$DQ$, $DQ$Bergungsprotokoll$DQ$, $DQ$memory$DQ$, $JB${"importance": 7, "content_en": "A complete record of what the flood carried and where it deposited. Understanding the flood's logic changes the agent's relationship to loss.", "content_de": "Ein vollständiges Protokoll dessen, was die Flut trug und wo sie es ablagerte. Das Verständnis der Logik der Flut verändert die Beziehung des Agenten zum Verlust."}$JB$::jsonb, $DQ$A complete record of what the flood carried and where it deposited. Understanding the flood$DQ$s logic changes the agent$DQ$s relationship to loss.$DQ$, $DQ$Ein vollständiges Protokoll dessen, was die Flut trug und wo sie es ablagerte. Das Verständnis der Logik der Flut verändert die Beziehung des Agenten zum Verlust.$DQ$, 25, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_flood_barrier_shard$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Flood Barrier Shard$DQ$, $DQ$Flutsperrensplitter$DQ$, $DQ$dungeon_buff$DQ$, $JB${"stress_damage_bonus": 0.5, "aptitude": "saboteur", "scope": "this_dungeon"}$JB$::jsonb, $DQ$A fragment of the barrier that held for 200 years. Applied to sabotage, the particle physics of resistance.$DQ$, $DQ$Ein Fragment der Sperre, die 200 Jahre hielt. Auf Sabotage angewandt, die Teilchenphysik des Widerstands.$DQ$, 25, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_tidal_insight$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Tidal Insight$DQ$, $DQ$Gezeiteneinsicht$DQ$, $DQ$dungeon_buff$DQ$, $JB${"check_bonus": 10, "aptitude": "spy", "scope": "this_dungeon"}$JB$::jsonb, $DQ$The tide$DQ$s pattern, internalized. Spy checks +10%.$DQ$, $DQ$Das Muster der Gezeiten, verinnerlicht. Spion-Proben +10%.$DQ$, 20, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_covenant_fragment$DQ$, $DQ$The Deluge$DQ$, 3, $DQ$Covenant Fragment$DQ$, $DQ$Bundesfragment$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "guardian", "boost": 1}$JB$::jsonb, $DQ$A fragment of the promise the water made: to recede, eventually. Carrying it changes how {agent} relates to protection. Guardian aptitude +1.$DQ$, $DQ$Ein Fragment des Versprechens, das das Wasser gab: sich zurückzuziehen, irgendwann. Es zu tragen verändert, wie {agent} sich zu Schutz verhält. Wächter-Aptitude +1.$DQ$, 40, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_deep_time_core$DQ$, $DQ$The Deluge$DQ$, 3, $DQ$Deep-Time Core$DQ$, $DQ$Tiefzeitkern$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "spy", "boost": 1}$JB$::jsonb, $DQ$Compressed sediment from the lowest floor. It contains the memory of every room the water passed through. Perception sharpened. Spy aptitude +1.$DQ$, $DQ$Komprimiertes Sediment vom tiefsten Stockwerk. Es enthält die Erinnerung an jeden Raum, den das Wasser durchquerte. Wahrnehmung geschärft. Spion-Aptitude +1.$DQ$, 35, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_elemental_warding$DQ$, $DQ$The Deluge$DQ$, 3, $DQ$Elemental Warding$DQ$, $DQ$Elementarschutz$DQ$, $DQ$simulation_modifier$DQ$, $JB${"building_protection": true, "duration_ticks": 10, "min_condition": "moderate", "description_en": "One building becomes immune to condition degradation below 'moderate' for 10 heartbeat ticks. The flood's inverse: preservation.", "description_de": "Ein Gebäude wird immun gegen Zustandsverschlechterung unter 'moderat' für 10 Herzschlag-Ticks. Das Inverse der Flut: Bewahrung."}$JB$::jsonb, $DQ$One building in the simulation becomes immune to condition degradation below $DQ$moderate$DQ$ for 10 heartbeat ticks. The flood$DQ$s inverse: preservation.$DQ$, $DQ$Ein Gebäude in der Simulation wird immun gegen Zustandsverschlechterung unter »moderat« für 10 Herzschlag-Ticks. Das Inverse der Flut: Bewahrung.$DQ$, 25, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_watermark$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A line. Mineral-white. Evidence.", "text_de": "Eine Linie. Mineralweiß. Beweis."}, "echo": {"text_en": "{agent} checks the watermark. It's higher.", "text_de": "{agent} prüft das Wasserzeichen. Es ist höher."}, "mutation": {"text_en": "The watermark moves while the party watches.", "text_de": "Das Wasserzeichen bewegt sich, während die Gruppe zusieht."}, "climax": {"text_en": "Both watermarks converge at the ceiling.", "text_de": "Beide Wasserzeichen laufen an der Decke zusammen."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_seal$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A seal. Intact. Holding something back.", "text_de": "Ein Siegel. Intakt. Hält etwas zurück."}, "echo": {"text_en": "The seal shows hairline cracks. {agent} examines.", "text_de": "Das Siegel zeigt Haarrisse. {agent} untersucht."}, "mutation": {"text_en": "The seal is wet on the inside.", "text_de": "Das Siegel ist innen nass."}, "climax": {"text_en": "The seal dissolves. What it held is here.", "text_de": "Das Siegel löst sich auf. Was es hielt, ist hier."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_raft$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A piece of a raft. Someone planned.", "text_de": "Ein Stück eines Floßes. Jemand hat geplant."}, "echo": {"text_en": "The raft fragment floats in the current. Familiar.", "text_de": "Das Floßfragment treibt in der Strömung. Vertraut."}, "mutation": {"text_en": "The raft has been repaired. By the water.", "text_de": "Das Floß wurde repariert. Vom Wasser."}, "climax": {"text_en": "The raft is whole. It was always whole.", "text_de": "Das Floß ist ganz. Es war immer ganz."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_compass$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A compass. The needle points down.", "text_de": "Ein Kompass. Die Nadel zeigt nach unten."}, "echo": {"text_en": "{agent} consults the compass. It still points down.", "text_de": "{agent} konsultiert den Kompass. Er zeigt immer noch nach unten."}, "mutation": {"text_en": "The compass needle has rusted to its position.", "text_de": "Die Kompassnadel ist in ihrer Position verrostet."}, "climax": {"text_en": "The compass is underwater. The needle is still.", "text_de": "Der Kompass ist unter Wasser. Die Nadel ist ruhig."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_bottle$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A sealed bottle. Air inside.", "text_de": "Eine versiegelte Flasche. Luft darin."}, "echo": {"text_en": "The bottle has drifted to the other side of the room.", "text_de": "Die Flasche ist auf die andere Seite des Raums getrieben."}, "mutation": {"text_en": "The seal is degrading. Bubbles escape.", "text_de": "Das Siegel zersetzt sich. Blasen entweichen."}, "climax": {"text_en": "The bottle is empty. The air is in the water now.", "text_de": "Die Flasche ist leer. Die Luft ist jetzt im Wasser."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_depth_gauge$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A gauge. Calibrated for a depth this room hasn't reached. Yet.", "text_de": "Eine Anzeige. Kalibriert für eine Tiefe, die dieser Raum noch nicht erreicht hat. Noch nicht."}, "echo": {"text_en": "The gauge reads higher. {agent} didn't touch it.", "text_de": "Die Anzeige zeigt höher an. {agent} hat sie nicht berührt."}, "mutation": {"text_en": "The gauge is calibrated for THIS room now.", "text_de": "Die Anzeige ist jetzt für DIESEN Raum kalibriert."}, "climax": {"text_en": "The gauge reads exactly 100. It was always going to.", "text_de": "Die Anzeige zeigt genau 100 an. Das war immer so vorgesehen."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_photograph$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A photograph. Water-damaged. A room that looks like this one, dry.", "text_de": "Eine Fotografie. Wasserbeschädigt. Ein Raum, der aussieht wie dieser, trocken."}, "echo": {"text_en": "The photograph shows more water than before. {agent} looks closer.", "text_de": "Die Fotografie zeigt mehr Wasser als zuvor. {agent} schaut genauer hin."}, "mutation": {"text_en": "The photograph and the room are the same image.", "text_de": "Die Fotografie und der Raum sind dasselbe Bild."}, "climax": {"text_en": "The photograph IS the room. The room is the photograph, submerged.", "text_de": "Die Fotografie IST der Raum. Der Raum ist die Fotografie, überflutet."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_stone$DQ$, $DQ$The Deluge$DQ$, $JB${"discovery": {"text_en": "A stone. Smooth. River-polished over centuries.", "text_de": "Ein Stein. Glatt. Vom Fluss poliert über Jahrhunderte."}, "echo": {"text_en": "{agent} feels the stone's weight differently. Heavier.", "text_de": "{agent} spürt das Gewicht des Steins anders. Schwerer."}, "mutation": {"text_en": "The stone is wet even above the waterline.", "text_de": "Der Stein ist nass, selbst über der Wasserlinie."}, "climax": {"text_en": "The stone sinks through the floor. The floor is water.", "text_de": "Der Stein sinkt durch den Boden. Der Boden ist Wasser."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$The stairs descend. The last three steps are wet. Not splashed – saturated. The water has been here before and left a mineral signature. It will return.$DQ$, $DQ$Die Treppe führt hinab. Die letzten drei Stufen sind nass. Nicht bespritzt – durchtränkt. Das Wasser war schon hier und hinterließ eine mineralische Signatur. Es wird zurückkehren.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$Dripping. Rhythmic. The sound precedes the dungeon – a metronome set by geology. {agent} counts the interval. 3.2 seconds. The interval will shorten.$DQ$, $DQ$Tropfen. Rhythmisch. Das Geräusch geht dem Dungeon voraus – ein von der Geologie eingestelltes Metronom. {agent} zählt das Intervall. 3,2 Sekunden. Das Intervall wird sich verkürzen.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$The air is different here. Humid. Heavy. The kind of air that has passed through water recently and carries its memory. Salt. Mineral. Patience.$DQ$, $DQ$Die Luft ist hier anders. Feucht. Schwer. Die Art Luft, die kürzlich durch Wasser ging und seine Erinnerung trägt. Salz. Mineral. Geduld.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$A watermark on the entrance arch. Faint. Mineral-white. Evidence of a previous visit by something that does not knock.$DQ$, $DQ$Ein Wasserzeichen am Eingangsbogen. Schwach. Mineralweiß. Beweis für einen früheren Besuch durch etwas, das nicht anklopft.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$The threshold is damp. Beyond it, the floor slopes downward – gently, deliberately. The architecture was designed for drainage. The drainage has failed.$DQ$, $DQ$Die Schwelle ist feucht. Dahinter fällt der Boden ab – sanft, absichtlich. Die Architektur wurde für Entwässerung entworfen. Die Entwässerung hat versagt.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 0, $DQ$The level is silent.$DQ$, $DQ$Der Pegel schweigt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 1, $DQ$The level speaks.$DQ$, $DQ$Der Pegel spricht.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 2, $DQ$The level insists.$DQ$, $DQ$Der Pegel besteht.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 3, $DQ$The level is correct.$DQ$, $DQ$Der Pegel hat Recht.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
